import{_ as o,o as t,c as e,f as i}from"./app-19f36e20.js";const c="/godot/images/body.drawio.svg",s={},d=i('<h1 id="物体、物理体之间的关系" tabindex="-1"><a class="header-anchor" href="#物体、物理体之间的关系" aria-hidden="true">#</a> 物体、物理体之间的关系？</h1><div class="custom-container tip"><p class="custom-container-title">物体、物理体之间的关系？</p><p>物理体，就是受到 Godot 物理系统影响<code>例如，重力等</code>的物体。</p></div><p>在 Godot 中，物理学主要基于 <strong>物体(Body)</strong> 和碰撞形状(Shape)。其中，物体（Object）是指在游戏世界中存在的实体。它可以是角色、道具、环境元素等。物体可以具有位置、旋转、缩放等属性，并且可以在游戏中进行移动、交互和与其他物体发生碰撞。</p><p>然而，模拟物理世界中的物体被称为<strong>物理体(Physic Body)</strong>，用来模拟物体之间的运动和相互作用以及与环境的相互作用。如果你想定义物理体，可以试试以下节点：</p><ul><li>Static Body（静止体）：在游戏中不移动但与其他对象交互的对象。</li><li>Rigid Body（刚体）：与物理引擎交互并受其影响的对象。</li><li>Kinematic Body (运动体)：不受物理直接影响但需要移动和检测碰撞的对象。</li></ul><p><img src="'+c+'" alt="body"></p>',6),a=[d];function n(r,l){return t(),e("div",null,a)}const p=o(s,[["render",n],["__file","body.html.vue"]]);export{p as default};
